  ('fire-eq-tech-moex-02590', 'fire-eq-tech', 'fire-eq-tech-moex-100-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依瓦斯漏氣檢知器之裝置規定，若測漏之瓦斯為LPG（液化石油氣），則下列規定何者正確？', '["檢知器上端，裝設在距樓地板面30公分範圍內", "設於距瓦斯燃燒器具或瓦斯導管貫穿牆壁處水平距離8公尺以內", "樓板有淨高60公分以上之樑或類似構造體時，設於近瓦斯燃燒器具或瓦斯導管貫穿牆壁處", "無須設置瓦斯漏氣檢知器"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "c70ccee8d47f", "answer_pdf_sha1": "12850e9e4ccc", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
