  ('fire-eq-tech-moex-02594', 'fire-eq-tech', 'fire-eq-tech-moex-100-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '某高層建築物，其總樓地板面積在三萬平方公尺以上。其主要避難路徑上之出口標示燈及避難方向指示 燈之緊急電源容量，應能使其有效動作多少分鐘以上？', '["10", "20", "40", "60"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "c70ccee8d47f", "answer_pdf_sha1": "12850e9e4ccc", "source_family": "moex-gov-tw", "moex": {"exam_code": "100090", "c": "902", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "100", "exam_name": "100年專技引水、驗船、第1次食品技師、消防設備、地政士、專責報關、保險人員、特考中醫、語言治療、聽力、牙體技術考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
